      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(f, 'ma_dvcs');
  changeLookupReadonly(f, 'ds_tt', true);
  f.setReferenceKeyFilter('ma_ku');
}
function close$VoucherFilter$(f) {
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, dFrom = f.getItem('tu_ngay').value, dTo = f.getItem('den_ngay').value, x = f.getItemValue('mau_bc'), c = $func.trim(f.getItemValue('tk'));
      g._alterTitle = [null, [['%d1', dFrom, true], ['%d2', dTo, true], ['%s', c ? c : '*', true]]];
      g._hiddenFields = [
        {Fields: 'du_dk_nt, ps_no_nt, ps_co_nt, du_ck_nt', Value: (x == '10')},
        {Fields: 'du_dk, ps_no, ps_co, du_ck', Value: (x == '20')}
      ];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function onChange$LoanContractType(o) {
  var f = o.parentForm;
  f.setReferenceKeyFilter('ma_ku');
}
